rule.positive_fixture:
template:
  sensor:
    - name: "Failing Counter"
      state: >
        {% set my_list = [] %}
        {% for i in range(5) %}
          {% set my_list = my_list + [i] %}
        {% endfor %}
        {{ my_list | count }}

rule.negative_fixture:
template:
  sensor:
    - name: "Working Counter"
      state: >
        {% set ns = namespace(my_list=[]) %}
        {% for i in range(5) %}
          {% set ns.my_list = ns.my_list + [i] %}
        {% endfor %}
        {{ ns.my_list | count }}

template:
  sensor:
    - name: "Last Seen Local"
      state: >
        {% set dt = as_datetime(states('input_datetime.last_seen')) %}
        {% if dt is not none %}
          {{ dt | as_local }}
        {% else %}
          'Unknown'
        {% endif %}
